scripts.postResponse:
rq.test('Status is 200', function(){ rq.response.to.have.status(200); });
let json = {}; try { json = rq.response.json(); } catch(e) {}
rq.test('Invoice payload returned', function(){ rq.expect(json.id || json.invoice_number).to.exist; });
if (json.paystack_reference) rq.collectionVariables.set('invoice_reference', json.paystack_reference);
